# 触发漏洞：offset = 100，使remaining = 64-100 = -36，memcpy复制大量数据
r = process('./vuln')
r.sendlineafter("offset: ", b"100")
r.sendafter("input: ", payload)
r.interactive()


**实际案例**：CVE-2019-2215（Android内核整数溢出）中，`binder`驱动存在类似减法溢出，导致内核栈溢出。攻击者通过ioctl控制offset，触发栈溢出，提升权限。

**修复**：使用无符号类型并检查offset是否大于BUFSIZE，或使用`if (offset >= BUFSIZE) return;`。

整数溢出在类型转换中可能导致信息泄露，常见于将大位宽整数赋值给小位宽变量时发生截断，但后续又将其恢复为大位宽，导致高位数据丢失。另一种情况是符号扩展：将有符号短整数赋值给有符号长整数时，负数会进行符号扩展，可能泄露原本不存在的内存内容。

**漏洞原理**：例如，内核从用户空间接收一个32位长度值，但内部存储为16位，然后返回给用户时又扩展回32位。若用户提供0xFFFF（16位最大值），扩展后为0x0000FFFF，但若内核内部使用有符号16位，则0xFFFF作为有符号是-1，扩展为32位后变成0xFFFFFFFF，导致用户看到巨大值，可能泄露内核地址。

**C代码示例**：
c
#include <stdio.h>
#include <stdint.h>

void kernel_function(uint32_t user_len) {
    uint16_t internal_len = (uint16_t)user_len;  // 截断
    // 假设内核处理后将internal_len返回给用户
    uint32_t returned_len = (uint32_t)internal_len;  // 零扩展
    printf("Returned: 0x%x\n", returned_len);
}

int main() {
    kernel_function(0x10001);  // 截断为0x0001，返回0x1，无泄露
    // 但若使用有符号类型：
    int16_t signed_internal = (int16_t)user_len;  // 若user_len=0xFFFF，signed_internal=-1
    int32_t signed_returned = (int32_t)signed_internal;  // 符号扩展为0xFFFFFFFF
    // 用户得到0xFFFFFFFF，可能包含内核地址信息（若该值原本是内核指针的一部分）
    return 0;
}


**利用方式**：攻击者通过发送特定值，使内核返回一个经过符号扩展的值，该值可能包含内核栈或堆上的残留数据，从而泄露ASLR基址或其他敏感信息。

**实际案例**：CVE-2016-0728（Linux内核keyring整数溢出）中，存在类似问题导致信息泄露，但更常见的是CVE-2017-5123（Linux内核waitid系统调用）中，通过整数溢出泄露内核地址。

**代码示例（Python）**：
python
from pwn import *

# 假设通过ioctl调用内核函数
r = process('./kernel_module')
# 发送0xFFFF作为长度
r.send(p32(0xFFFF))
# 接收返回的32位值
leak = u32(r.recv(4))
print(f"Leaked value: {hex(leak)}")
# 若leak为0xFFFFFFFF，可能包含内核地址高位


**修复**：使用相同位宽类型，避免截断和符号扩展，或使用掩码操作。

整数溢出在循环计数中导致无限循环，常见于使用无符号整数作为循环变量且循环条件为`i > 0`，当i递减到0后继续减1，i变为最大值，循环永不结束。这种漏洞可被利用进行拒绝服务攻击，消耗CPU和内存资源。

**漏洞原理**：例如`for (unsigned int i = len; i > 0; i--)`，若len为0，则循环体不执行。但若循环体内部先递减再检查，如`while (len-- > 0)`，则当len=0时，len--结果为0，循环体执行一次后len变为UINT_MAX，后续循环无限。

**C代码示例**：
c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void vulnerable_loop(unsigned int count) {
    char *buffer = (char*)malloc(1024);
    if (!buffer) return;
    unsigned int i = count;
    while (i-- > 0) {  // 当count=0时，i初始0，i--值为0，循环体执行，然后i=UINT_MAX
        buffer[i % 1024] = 'A';  // 无限循环，不断写入
    }
    free(buffer);
}

int main() {
    vulnerable_loop(0);  // 触发无限循环
    return 0;
}


**利用方式**：攻击者控制count为0，使程序陷入无限循环，占用CPU 100%，导致拒绝服务。若循环内进行内存分配（如malloc），则会导致内存耗尽。

**实际案例**：CVE-2018-5733（Bind 9）中存在类似整数溢出导致无限循环，攻击者发送特制DNS查询，使服务器陷入死循环，服务不可用。

**修复**：使用前置递减检查：`while (i > 0) { i--; ... }`，或使用`for (unsigned int i = 0; i < count; i++)`。

无符号整数环绕（Unsigned Integer Wrapping）是指当无符号整数运算结果超过其类型最大值时，结果会回绕到最小值重新开始。例如，对于32位无符号整数，0xFFFFFFFF + 1 = 0x00000000。这种特性在内存分配、循环计数或长度计算中常被利用，导致缓冲区溢出。

**CVE-2019-2215** 是Android内核Binder驱动中的整数溢出漏洞，影响Android 4.4至10。漏洞成因：在`binder_ioctl`函数中，用户传入的`binder_version`结构体大小通过`copy_from_user`复制，但未正确验证`size`参数。当`size`为0时，后续计算`alloc_size = size + sizeof(struct binder_proc)`导致整数环绕，分配过小内存，后续写入越界。

**POC原理**：攻击者通过ioctl传入`size=0xFFFFFFFF`（实际会截断？更准确是传入`size`使`alloc_size`环绕为小值），导致内核分配极小的缓冲区，然后写入大量数据造成堆溢出，可提权。

**修复**：在`binder_ioctl`中添加检查，确保`size`不超过`sizeof(struct binder_version)`，并避免整数溢出。

以下是一个简化的C代码示例，演示无符号整数环绕导致缓冲区溢出：
c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void vulnerable_function(unsigned int size) {
    // 假设我们想分配 size + 10 字节
    unsigned int alloc_size = size + 10;  // 如果 size 接近 0xFFFFFFFF，alloc_size 环绕为小值
    char *buffer = (char*)malloc(alloc_size);
    if (!buffer) return;
    // 假设后续写入 size 字节的数据，但实际分配很小
    memset(buffer, 'A', size);  // 缓冲区溢出
    free(buffer);
}

int main() {
    vulnerable_function(0xFFFFFFF6);  // 0xFFFFFFF6 + 10 = 0x100000000 -> 环绕为0
    return 0;
}

该代码中，`size=0xFFFFFFF6`时，`alloc_size`环绕为0，`malloc(0)`可能返回一个有效指针（实现相关），但后续`memset`写入大量数据导致堆溢出。实际利用中，攻击者可通过控制溢出数据覆盖相邻堆块元数据或函数指针实现代码执行。

有符号整数溢出（Signed Integer Overflow）是指有符号整数运算结果超出其表示范围，在C标准中属于未定义行为（Undefined Behavior）。编译器可能优化掉溢出检查，导致逻辑错误。攻击者常利用溢出绕过长度检查，分配过小内存，随后写入大量数据造成堆溢出。

**CVE-2021-3156** 是sudo中的堆溢出漏洞，影响sudo 1.8.2至1.8.31p2。漏洞成因：在`sudoers`的`set_cmnd`函数中，当处理包含反斜杠转义的命令行参数时，计算新字符串长度时使用了有符号整数加法。如果输入参数长度接近INT_MAX，加法溢出为负数，导致后续`malloc`分配极小内存，然后`strcpy`写入超长数据。

**POC原理**：攻击者构造一个极长的命令行参数（例如通过`sudoedit -s`），触发长度计算溢出，分配过小堆缓冲区，然后复制数据时覆盖堆元数据，最终可提权至root。

**修复**：在sudo 1.8.31p3中，改用无符号整数运算并添加溢出检查。

以下是一个简化的C代码演示有符号整数溢出导致堆溢出：
