#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void vulnerable(unsigned int user_len) {
    unsigned short alloc_len = (unsigned short)user_len;  // 截断
    char *buf = (char*)malloc(alloc_len);
    if (!buf) return;
    // 假设后续写入 user_len 字节
    memset(buf, 'A', user_len);  // 越界写入
    free(buf);
}

int main() {
    vulnerable(0x10001);  // 截断后 alloc_len = 1，但写入0x10001字节
    return 0;
