    unsigned char alloc_len = (unsigned char)len;  // 256 -> 0
    char buf[alloc_len];  // 实际上C99 VLA，但分配0字节
    // 假设从网络读取len字节到buf
    memset(buf, 'A', (unsigned int)len);  // 栈溢出
}

int main() {
