    if (argc < 2) return 1;
    int len = atoi(argv[1]);
    char *input = "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA";
    vulnerable(input, len);
    return 0;
