#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

void vulnerable(size_t a, size_t b) {
    size_t size = a + b;  // 无符号环绕
    char *buf = (char*)malloc(size);
    if (!buf) return;
    // 假设后续从用户态拷贝了a+b字节的数据，但实际buf只有size字节（可能很小）
    // 这里模拟拷贝超出分配大小
    char *payload = (char*)malloc(a + b);
    if (!payload) { free(buf); return; }
    memset(payload, 'A', a + b);
    memcpy(buf, payload, a + b);  // 堆溢出
    free(buf);
    free(payload);
}

int main() {
    // 触发环绕：a=0xffffffff, b=0x1 => size=0
    vulnerable(0xffffffff, 0x1);
    return 0;
}

实际利用中，攻击者通过精心构造a和b的值使size极小（如0），malloc(0)可能返回一个有效指针（取决于实现），然后大量数据拷贝覆盖相邻堆块，可改写堆元数据或函数指针。修复方法：在加法前检查是否溢出，或使用安全函数如`calloc`（内部乘除检查）或`size_t`比较。

整数环绕（wraparound）是无符号整数运算中常见的一种漏洞，当计算结果超出类型所能表示的最大值时，会自动回绕到最小值继续计算。例如，对于32位无符号整数，0xFFFFFFFF + 1 = 0x00000000。这种特性在内存分配、长度计算等场景中可被利用来绕过安全检查。

典型利用场景：在glibc的malloc中，如果分配大小由用户控制且经过加法运算，可能发生环绕导致分配过小的堆块，后续写入时造成堆溢出。

**漏洞代码示例（C语言）：**
c
#include <stdlib.h>
#include <string.h>
#include <stdio.h>

void vulnerable(size_t len1, size_t len2) {
    size_t total = len1 + len2;  // 整数环绕可能发生
    char *buf = (char*)malloc(total);
    if (!buf) return;
    // 假设后续从用户输入拷贝len1+len2字节，但实际分配可能小于预期
    // 例如 len1=0x80000000, len2=0x80000000 => total=0，malloc(0)返回小堆块
    // 后续拷贝大量数据导致堆溢出
    // 实际利用中会精心构造len1和len2使total恰好为小值
}


**利用思路（pwntools示例）：**
假设目标程序允许用户提供两个长度参数，内部相加后分配缓冲区，然后从用户输入拷贝数据。攻击者可以设置len1=0x80000001, len2=0x7FFFFFFF，使得total=0x100000000（溢出为0），malloc(0)返回一个极小堆块（通常16字节）。然后程序会尝试拷贝0x100000000字节数据，但实际堆块只有16字节，导致堆溢出覆盖相邻堆块元数据，最终控制执行流。

**防御：** 在加法前检查是否溢出，或使用安全函数如`__builtin_add_overflow`。

该漏洞在CVE-2015-0235（Ghost）中也有体现，但更经典的堆分配环绕是CVE-2009-1385（Linux内核e1000驱动）。

有符号到无符号转换漏洞发生在将有符号整数隐式或显式转换为无符号类型时，负值会被解释为极大的无符号数。这在数组索引、内存拷贝长度等场景中可导致越界访问。

**漏洞原理：** C语言中，当有符号int与无符号size_t混合运算时，有符号数会被隐式转换为无符号。例如，int a = -1; size_t b = a; 则b等于0xFFFFFFFF（32位）。如果b用作数组索引，将访问数组边界之外的内存。

**漏洞代码示例：**
c
#include <stdio.h>
#include <string.h>

void vulnerable(int index, char *data, size_t len) {
