#include <stdlib.h>
#include <string.h>
#include <stdio.h>

void vulnerable(uint64_t huge_size) {
    // 假设huge_size来自用户输入，例如0x100000001
    unsigned int small_size = (unsigned int)huge_size;  // 截断为0x00000001
    char *buf = (char*)malloc(small_size);  // 只分配1字节
    if (!buf) return;
    // 后续从用户输入拷贝huge_size字节数据
    // 实际拷贝0x100000001字节，但堆块只有1字节，导致堆溢出
    // 注意：memcpy第三个参数是size_t，可能也是64位，但huge_size未截断
    memcpy(buf, user_input, huge_size);  // 溢出
}


