#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void vulnerable(size_t user_size) {
    int alloc_size = (int)user_size;  // 截断
    char *buf = (char*)malloc(alloc_size);
    if (!buf) return;
    // 假设后续写入 user_size 长度的数据（实际远大于 alloc_size）
    memset(buf, 0x41, user_size);  // 堆溢出
    free(buf);
}

int main() {
    // 触发截断：user_size = 0x100000001 => alloc_size = 1
    vulnerable(0x100000001);
    return 0;
}


**修复**：微软在更新中将变量类型改为 `size_t`，并添加了大小检查。开发者应避免不同宽度整数之间的隐式转换，使用 `size_t` 或显式检查范围。

无符号整数环绕在循环中可能导致循环计数器意外回绕，造成无限循环或越界内存访问。常见于使用无符号整数作为循环变量且递减到0后继续减1的情况。

**漏洞原理**：例如 `for (unsigned i = n; i >= 0; i--)`，当 `i` 为0时，`i--` 得到 `UINT_MAX`，由于 `i >= 0` 永远为真，循环无限执行。若循环体内有数组写入操作，每次迭代写入 `arr[i]`，当 `i` 变为极大值时，写入地址远超出数组边界，导致越界写。

**利用思路**：攻击者控制循环起始值 `n`，使循环在预期次数后继续执行，覆盖栈上返回地址或堆上关键数据。

**代码示例（C语言）**：
c
#include <stdio.h>
#include <string.h>

void vulnerable(unsigned int n) {
    char buf[64];
    // 循环条件错误：i >= 0 永远为真
    for (unsigned int i = n; i >= 0; i--) {
        if (i < sizeof(buf)) {
            buf[i] = 'A';  // 当i=0后，i变为UINT_MAX，越界写
        }
    }
}

int main() {
    vulnerable(10);  // 循环从10到0，然后继续到UINT_MAX
    return 0;
}


