#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void vulnerable(unsigned int count, unsigned int elem_size) {
    unsigned int total = count * elem_size;  // 整数环绕
    char *buf = (char*)malloc(total);
    if (!buf) return;
    // 假设后续写入 count 个 elem_size 大小的元素
    for (unsigned int i = 0; i < count; i++) {
        memcpy(buf + i * elem_size, "AAAAAAAA", elem_size);  // 溢出
    }
    free(buf);
}

int main() {
    // count=0x10001, elem_size=0x10000 => total=0x10000 (环绕)
    vulnerable(0x10001, 0x10000);
    return 0;
}


