#include <stdlib.h>
#include <string.h>

void decompress(unsigned int original_size, unsigned int offset) {
    unsigned int decompressed_size = original_size - offset;  // 可能下溢
    printf("Original: %u, Offset: %u, Decompressed: %u\n", original_size, offset, decompressed_size);
    // 假设分配decompressed_size字节的缓冲区
    char *buffer = (char *)malloc(decompressed_size);
    if (buffer == NULL) return;
    // 假设后续解压写入original_size字节的数据（实际数据更大）
    // 如果decompressed_size很小，则发生堆溢出
    // 例如：original_size=0x1000, offset=0x2000, decompressed_size=0xFFFFF000（32位下溢为0xFFFFF000，但实际分配时可能被截断？）
    // 在32位系统上，0x1000-0x2000 = 0xFFFFF000（约4GB），malloc可能失败或分配巨大内存
    // 但在64位系统上，无符号减法结果也是64位，但后续可能被截断为32位
    // 实际漏洞中，decompressed_size被用作32位值，导致下溢为0xFFFFF000，但分配时可能被截断为0xFFFFF000（约4GB），malloc失败
    // 但攻击者可以构造更小的值，例如original_size=0x100, offset=0x200，得到0xFFFFFF00，分配约4GB-256字节，可能成功？
    // 更精确的POC需要逆向实际驱动，这里仅演示原理
    free(buffer);
}

int main() {
    decompress(0x1000, 0x2000);  // 下溢
    return 0;
}


