    // 循环中计算索引：index = offset + i，其中i从0到count-1
    // 如果offset很大，例如0x7FFFFFFF，加上i后可能溢出为负数
    for (int i = 0; i < count; i++) {
        int index = offset + i;  // 有符号整数可能溢出
        if (index < 0 || index >= 10) {
            printf("Index out of bounds\n");
            continue;
        }
        // 访问array[index]
        printf("array[%d] = %d\n", index, array[index]);
    }
}

int main() {
    // 攻击者可以传入offset=0x7FFFFFFF, count=2
    // 第一次循环：index=0x7FFFFFFF+0=0x7FFFFFFF，检查失败
    // 第二次循环：index=0x7FFFFFFF+1=0x80000000（负数），检查失败
    // 但如果我们能绕过检查？实际上检查会阻止。
    // 更隐蔽的情况：检查使用了无符号比较，或者检查不完整。
    // 例如，如果检查是 if (index > 10) 而不是 if (index < 0 || index >= 10)，那么负数会通过检查（因为负数转换为无符号后很大）
    // 我们修改检查为：if (index > 10) return;  // 错误
    // 那么index=-1（0xFFFFFFFF）大于10，会被拒绝？实际上0xFFFFFFFF > 10为真，所以也被拒绝。
    // 正确的绕过：使用无符号索引，且检查只检查上限，不检查下限。
    // 例如：
    unsigned int uindex = (unsigned int)index;
    if (uindex >= 10) return;  // 负数转换为无符号后很大，所以被拒绝
    // 所以需要更巧妙的溢出：例如索引计算中使用乘法，导致结果回绕到小值。
    return 0;
}


更实际的利用场景：在图像处理或协议解析中，索引通过乘法计算，例如`index = row * width + col`，如果row和col很大，乘法可能溢出，导致index很小，从而访问数组头部之前的内存。以下是一个利用乘法溢出的示例：
c
#include <stdio.h>
#include <stdlib.h>

char buffer[256];

void write_pixel(unsigned int row, unsigned int col, unsigned int width, char value) {
    // 假设width=256，row=0x10000，col=0，则row*width=0x1000000，但unsigned int可能溢出
    // 例如32位系统，0x10000*256=0x1000000，没有溢出。
    // 如果row=0x1000000，col=0，width=256，则row*width=0x100000000，溢出为0
    unsigned int index = row * width + col;  // 乘法可能溢出
    if (index >= 256) {
        printf("Out of bounds\n");
        return;
    }
    buffer[index] = value;  // 如果index=0，则写入buffer[0]，但实际row很大，导致越界？
    // 实际上，如果乘法溢出为0，则写入buffer[0]，但row很大，这并没有越界，只是写到了错误位置。
    // 要越界，需要index大于255，但乘法溢出通常产生小值。
    // 另一种情况：有符号整数乘法溢出导致负数，然后被用作索引。
    return;
}


利用pwntools实现任意地址读写通常需要结合其他漏洞，例如堆溢出或格式化字符串。但这里我们可以演示一个假设场景：程序允许通过索引读写数组，且索引计算存在整数溢出，攻击者可以构造索引指向栈上的返回地址。以下是一个简化的pwntools脚本，假设目标程序有漏洞函数，通过输入offset和count，可以越界读取栈上的值：
